async (params, browser) => {
  // Open Quora homepage
  await browser.open('https://www.quora.com/')

  // Wait for feed
  await browser.waitForSelector('[class*=\'Question\'], [class*=\'question\'], [class*=\'feed\']', 15000)

  await browser.wait(2000)

  // Scroll feed
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(2000)

  // Scroll more
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(1500)

  // Extract trending content
  const trending_data = await browser.evaluate(`const trending = []; const feedItems = document.querySelectorAll('[class*="feed"] > div, [class*="Question"], [class*="pagedList"] > div'); for (let i = 0; i < Math.min(feedItems.length, 20); i++) { const el = feedItems[i]; const questionEl = el.querySelector('[class*="question_text"], [class*="Question"] a span'); const answerEl = el.querySelector('[class*="answer"], [class*="inline"]'); const authorEl = el.querySelector('[class*="user"] a, [class*="author"]'); const upvotesEl = el.querySelector('[class*="upvote"]'); const linkEl = el.querySelector('a[href*="/"]'); if (questionEl) { trending.push({ question: questionEl.textContent.trim(), answer_preview: answerEl ? answerEl.textContent.trim().substring(0, 300) : '', author: authorEl ? authorEl.textContent.trim() : '', upvotes: upvotesEl ? upvotesEl.textContent.trim() : '', url: linkEl ? linkEl.href : '' }); } } return { trending_count: trending.length, trending: trending, url: window.location.href }`)

  return trending_data
}
